import { useState, useEffect, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { ArrowLeft, Save, Plus, Trash2, Printer, Calendar } from "lucide-react";
import Select from "react-select";
import {
  collection,
  getDocs,
  addDoc,
  updateDoc,
  doc,
  getDoc,
  query,
  where,
} from "firebase/firestore";
import { getDB } from "../firebase";
import "./AddVoucher.css";

function AddVoucher() {
  const db = getDB();
  const { id } = useParams();
  const navigate = useNavigate();

  const [parties, setParties] = useState([]);
  const [products, setProducts] = useState([]);

  const [loading, setLoading] = useState(false);
  const productSelectRef = useRef(null);

  const [voucher, setVoucher] = useState({
    date: new Date().toISOString().split("T")[0],
    partyId: "",
    items: [],
    note: "",
    paymentMethod: "Cash",
    status: "Paid",
    paidAmount: 0,
  });

  // Load parties and products for dropdowns
  useEffect(() => {
    const fetchData = async () => {
      try {
        const loggedCompanyId = JSON.parse(
          localStorage.getItem("loggedCompany"),
        )?.id;

        const partiesQ = query(
          collection(db, "parties"),
          where("companyId", "==", loggedCompanyId),
        );
        const partiesSnap = await getDocs(partiesQ);
        setParties(
          partiesSnap.docs.map((doc) => ({ id: doc.id, ...doc.data() })),
        );

        const productsQ = query(
          collection(db, "products"),
          where("companyId", "==", loggedCompanyId),
        );
        const productsSnap = await getDocs(productsQ);
        setProducts(
          productsSnap.docs.map((doc) => ({ id: doc.id, ...doc.data() })),
        );

        if (id) {
          const voucherSnap = await getDoc(doc(db, "vouchers", id));
          if (voucherSnap.exists()) {
            const data = voucherSnap.data();
            setVoucher({
              paymentMethod: "Cash",
              status: "Paid",
              paidAmount: 0,
              ...data,
            });
          }
        }
      } catch (error) {
        console.error("Error fetching data:", error);
      }
    };
    fetchData();
  }, [id, db]);

  const handleProductSelect = (selectedOptions) => {
    // Handle the multi-select options
    const newSelectedProducts = selectedOptions || [];

    // Map selected products to items, preserving existing row data (qty, price)
    const updatedItems = newSelectedProducts.map((option) => {
      const existingItem = voucher.items.find(
        (item) => item.productId === option.value,
      );
      if (existingItem) {
        return existingItem;
      }

      const productDef = products.find((p) => p.name === option.value);
      const price = productDef ? parseFloat(productDef.price) || 0 : 0;
      return {
        productId: option.value,
        name: productDef ? productDef.name : option.value,
        price: price,
        qty: 1,
        amount: price * 1,
        unit: productDef ? productDef.unit : "Pcs",
      };
    });

    setVoucher({ ...voucher, items: updatedItems });
  };

  const removeItem = (index) => {
    const newItems = voucher.items.filter((_, i) => i !== index);
    setVoucher({ ...voucher, items: newItems });
  };

  const handleItemChange = (index, field, value) => {
    const newItems = [...voucher.items];
    const item = { ...newItems[index] };

    item[field] = value;

    const qty = parseFloat(item.qty) || 0;
    const price = parseFloat(item.price) || 0;

    item.amount = price * qty;

    newItems[index] = item;
    setVoucher({ ...voucher, items: newItems });
  };

  const calculateTotals = () => {
    return voucher.items.reduce(
      (acc, item) => {
        acc.total += item.amount;
        return acc;
      },
      { total: 0 },
    );
  };

  const totals = calculateTotals();
  const remainingAmount = totals.total - (parseFloat(voucher.paidAmount) || 0);

  // Auto-sync paidAmount when status is 'Paid'
  useEffect(() => {
    if (voucher.status === "Paid" && voucher.paidAmount !== totals.total) {
      setVoucher((prev) => ({
        ...prev,
        paidAmount: totals.total,
      }));
    }
  }, [totals.total, voucher.status]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Clean up any stray empty items before saving
    const cleanedItems = voucher.items.filter((item) => item.productId);

    if (!voucher.partyId || cleanedItems.length === 0) {
      alert("Please select a party and add at least one valid item.");
      return;
    }

    setLoading(true);
    const finalVoucher = {
      ...voucher,
      items: cleanedItems,
      totalAmount: totals.total,
      remainingAmount: remainingAmount,
      companyId: JSON.parse(localStorage.getItem("loggedCompany"))?.id,
    };

    try {
      if (id) {
        await updateDoc(doc(db, "vouchers", id), finalVoucher);
      } else {
        // Assign creation timestamp if purely new
        finalVoucher.createdAt = Date.now();

        // Generate Invoice Number
        const loggedCompanyId = JSON.parse(
          localStorage.getItem("loggedCompany"),
        )?.id;
        const vouchersQ = query(
          collection(db, "vouchers"),
          where("companyId", "==", loggedCompanyId),
        );
        const vouchersSnap = await getDocs(vouchersQ);
        const nextInvoiceNum = `INV/25-26/${String(vouchersSnap.size + 1).padStart(3, "0")}`;
        finalVoucher.invoiceNumber = nextInvoiceNum;

        await addDoc(collection(db, "vouchers"), finalVoucher);
      }
      navigate("/vouchers");
    } catch (error) {
      console.error("Error saving voucher:", error);
      alert("Failed to save voucher. Check console for details.");
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = (newStatus) => {
    let newPaidAmount = voucher.paidAmount;

    if (newStatus === "Paid") {
      newPaidAmount = totals.total;
    } else if (newStatus === "Unpaid") {
      newPaidAmount = 0;
    }
    // For "Partial", we keep the current paid amount or let user edit

    setVoucher({
      ...voucher,
      status: newStatus,
      paidAmount: newPaidAmount,
    });
  };

  const handlePaidAmountChange = (val) => {
    const newPaidAmount = parseFloat(val) || 0;
    let newStatus = voucher.status;

    // Only flip to 'Paid' if the amount meets or exceeds the total
    if (newPaidAmount >= totals.total && totals.total > 0) {
      newStatus = "Paid";
    }

    setVoucher({
      ...voucher,
      paidAmount: val,
      status: newStatus,
    });
  };

  return (
    <div className="add-voucher-page">
      <header className="fixed-header no-print add-voucher-header">
        <button
          className="btn btn-outline btn-icon add-voucher-back-btn"
          onClick={() => navigate("/vouchers")}
          title="Back"
        >
          <ArrowLeft size={18} />
        </button>
        <h3 className="add-voucher-title">
          {id ? "Edit Voucher" : "New Voucher"}
        </h3>
      </header>

      <div className="content-below-fixed">
        <form onSubmit={handleSubmit}>
          {/* Voucher Header Info */}
          <div className="grid grid-2 voucher-header-info">
            <div className="form-group">
              <label className="form-label">Date</label>
              <div className="input-with-icon">
                <Calendar className="input-icon" size={18} />
                <input
                  type="date"
                  className="form-input"
                  value={voucher.date}
                  onChange={(e) =>
                    setVoucher({ ...voucher, date: e.target.value })
                  }
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Party</label>
              <Select
                menuPortalTarget={document.body}
                options={parties.map((p) => ({ value: p.name, label: p.name }))}
                value={
                  voucher.partyId
                    ? { value: voucher.partyId, label: voucher.partyId }
                    : null
                }
                onChange={(selected) =>
                  setVoucher({
                    ...voucher,
                    partyId: selected ? selected.value : "",
                  })
                }
                placeholder="Select Party"
                isClearable
                className="react-select-container"
                classNamePrefix="react-select"
              />
            </div>
          </div>

          {/* Multi-Select Products Section */}
          <div className="form-group av-products-group" ref={productSelectRef}>
            <label className="form-label">Products</label>
            <Select
              menuPortalTarget={document.body}
              isMulti
              isDisabled={!voucher.partyId}
              options={products.map((p) => ({ value: p.name, label: p.name }))}
              value={voucher.items.map((item) => ({
                value: item.productId,
                label: item.name,
              }))}
              onChange={handleProductSelect}
              placeholder={
                !voucher.partyId
                  ? "Please select a party first..."
                  : "Search and add multiple products..."
              }
              onFocus={() => {
                if (productSelectRef.current) {
                  setTimeout(() => {
                    productSelectRef.current.scrollIntoView({
                      behavior: "smooth",
                      block: "start",
                    });
                  }, 150);
                }
              }}
              className="react-select-container"
              classNamePrefix="react-select"
            />
          </div>

          {/* Items Section */}
          <div className="voucher-items-wrapper">
            <div className="voucher-items-header-row">
              <div className="voucher-col voucher-col-product">Product</div>
              <div className="voucher-col voucher-col-qty">QTY</div>
              <div className="voucher-col voucher-col-unit">UNIT</div>
              <div className="voucher-col voucher-col-price">Price</div>
              <div className="voucher-col voucher-col-total">Total</div>
            </div>

            <div className="voucher-items-list">
              {voucher.items.length > 0 ? (
                voucher.items.map((item, index) => (
                  <div key={index} className="voucher-item-row">
                    <div
                      className="voucher-cell voucher-col-product"
                      data-label="Product"
                    >
                      <strong>{item.name}</strong>
                    </div>
                    <div
                      className="voucher-cell voucher-col-qty av-qty-cell-content"
                      data-label="QTY"
                    >
                      <input
                        type="number"
                        className="form-input av-qty-input"
                        value={item.qty}
                        onChange={(e) =>
                          handleItemChange(index, "qty", e.target.value)
                        }
                      />
                    </div>
                    <div
                      className="voucher-cell voucher-col-unit"
                      data-label="UNIT"
                    >
                      <span className="av-qty-unit">{item.unit || "Pcs"}</span>
                    </div>
                    <div
                      className="voucher-cell voucher-col-price"
                      data-label="Price"
                    >
                      <input
                        type="number"
                        className="form-input"
                        value={item.price}
                        onChange={(e) =>
                          handleItemChange(index, "price", e.target.value)
                        }
                      />
                    </div>
                    <div
                      className="voucher-cell voucher-col-total"
                      data-label="Amount"
                    >
                      <span>{Number(item.amount || 0).toFixed(2)}</span>
                    </div>
                  </div>
                ))
              ) : (
                <div className="av-empty-state">No products selected.</div>
              )}
            </div>
          </div>

          <div className="grid grid-2 voucher-header-info">
            <div className="form-group">
              <label className="form-label">Voucher Status</label>
              <Select
                menuPortalTarget={document.body}
                options={[
                  { value: "Unpaid", label: "Unpaid" },
                  { value: "Partial", label: "Partial" },
                  { value: "Paid", label: "Paid" },
                ]}
                value={{ value: voucher.status, label: voucher.status }}
                onChange={(selected) => handleStatusChange(selected.value)}
                className="react-select-container"
                classNamePrefix="react-select"
              />
            </div>
            <div className="form-group">
              <label className="form-label">Payment Method</label>
              <Select
                menuPortalTarget={document.body}
                isDisabled={voucher.status === "Unpaid"}
                options={[
                  { value: "Cash", label: "Cash" },
                  { value: "Online", label: "Online" },
                ]}
                value={{
                  value: voucher.paymentMethod,
                  label: voucher.paymentMethod,
                }}
                onChange={(selected) =>
                  setVoucher({ ...voucher, paymentMethod: selected.value })
                }
                className="react-select-container"
                classNamePrefix="react-select"
              />
            </div>
          </div>

          <div className="voucher-totals-container">
            {voucher.status === "Partial" && (
              <div className="voucher-payment-calcs">
                <div className="form-group">
                  <label className="form-label">Amount Paid (Ôé╣)</label>
                  <input
                    type="number"
                    className="form-input"
                    min="0"
                    value={voucher.paidAmount}
                    onChange={(e) => handlePaidAmountChange(e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Balance Remaining (Ôé╣)</label>
                  <input
                    type="text"
                    className={`form-input av-balance-input ${remainingAmount > 0 ? "av-balance-due" : "av-balance-clear"}`}
                    value={remainingAmount.toFixed(2)}
                    readOnly
                  />
                </div>
              </div>
            )}

            <div className="voucher-total-block">
              <h3 className="voucher-total-label">Total</h3>
              <h3 className="voucher-grand-total-value">
                Ôé╣{totals.total.toFixed(2)}
              </h3>
            </div>
          </div>

          <div className="form-group voucher-notes-group">
            <label className="form-label">Notes</label>
            <textarea
              className="form-textarea"
              rows="2"
              value={voucher.note}
              onChange={(e) => setVoucher({ ...voucher, note: e.target.value })}
              placeholder="Payment terms, delivery notes, etc."
            />
          </div>

          <div className="voucher-actions">
            <button
              type="submit"
              className="btn btn-outline-primary btn-mobile-flex"
              disabled={loading}
            >
              {loading ? "Processing..." : "Save Voucher"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddVoucher;

import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Printer, ArrowLeft } from "lucide-react";
import {
  collection,
  getDocs,
  doc,
  getDoc,
  query,
  where,
} from "firebase/firestore";
import { getDB } from "../firebase";
import "./VoucherPrint.css";

function VoucherPrint() {
  const db = getDB();
  const { id } = useParams();
  const navigate = useNavigate();

  const [voucher, setVoucher] = useState(null);
  const [party, setParty] = useState(null);
  const [clientCompany, setClientCompany] = useState(null);

  useEffect(() => {
    const fetchVoucherData = async () => {
      try {
        const voucherRef = doc(db, "vouchers", id);
        const voucherSnap = await getDoc(voucherRef);

        if (voucherSnap.exists()) {
          const vData = voucherSnap.data();
          const targetCompanyId =
            vData.companyId ||
            JSON.parse(localStorage.getItem("loggedCompany"))?.id;

          let fetchedCompany =
            JSON.parse(localStorage.getItem("loggedCompany")) || {};
          if (targetCompanyId) {
            const compSnap = await getDoc(
              doc(db, "companies", targetCompanyId),
            );
            if (compSnap.exists()) {
              fetchedCompany = { id: compSnap.id, ...compSnap.data() };
            }
          }
          setClientCompany(fetchedCompany);

          let fallbackInvoiceNumber = "";
          if (!vData.invoiceNumber && targetCompanyId) {
            const vouchersQ = query(
              collection(db, "vouchers"),
              where("companyId", "==", targetCompanyId),
            );
            const allVouchersSnap = await getDocs(vouchersQ);
            let data = allVouchersSnap.docs.map((d) => ({
              id: d.id,
              ...d.data(),
            }));
            data.sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
            const myIndex = data.findIndex((d) => d.id === voucherSnap.id);
            fallbackInvoiceNumber = `INV/25-26/${String((myIndex !== -1 ? myIndex : 0) + 1).padStart(3, "0")}`;
          }

          setVoucher({ id: voucherSnap.id, fallbackInvoiceNumber, ...vData });

          // Fetch the associated party using query
          const q = query(
            collection(db, "parties"),
            where("name", "==", vData.partyId),
          );
          const partySnap = await getDocs(q);

          if (!partySnap.empty) {
            setParty(partySnap.docs[0].data());
          } else {
            setParty({ name: vData.partyId }); // Fallback if party deleted
          }
        } else {
          console.error("No such voucher!");
          if (localStorage.getItem("loggedCompany")) {
            navigate("/vouchers");
          } else {
            navigate(-1);
          }
        }
      } catch (error) {
        console.error("Error fetching voucher for print:", error);
      }
    };

    if (id) {
      fetchVoucherData();
    }
  }, [id, navigate]);

  const handlePrint = () => {
    window.print();
  };

  if (!voucher) return <div>Loading...</div>;

  const calculateTotal = (items) =>
    items.reduce((sum, item) => sum + (Number(item.amount) || 0), 0);

  return (
    <div className="print-container">
      <div className="fixed-header no-print print-page-header">
        <button
          className="btn btn-outline btn-icon print-back-btn"
          onClick={() => {
            if (localStorage.getItem("loggedCompany")) {
              navigate("/vouchers");
            } else {
              navigate(-1);
            }
          }}
          title="Back"
        >
          <ArrowLeft size={18} />
        </button>
        <h3 className="print-title-text">Print Preview</h3>
        <button
          className="btn btn-primary print-btn-right"
          onClick={handlePrint}
        >
          <Printer size={18} /> Print
        </button>
      </div>

      <div className="content-below-fixed printable-area">
        <div className="invoice-preview-card">
          {/* Header */}
          <div className="print-doc-header">
            <div className="print-header-content">
              <div className="print-logo-section">
                {clientCompany?.logo && (
                  <img
                    src={clientCompany.logo}
                    alt="Logo"
                    className="print-main-logo"
                  />
                )}
              </div>
              <div className="print-company-info-section">
                <h1 className="print-company-name">
                  {clientCompany?.companyName || "COMPANY NAME"}
                </h1>
                <div className="print-company-details">
                  <p>
                    <strong>Mobile:</strong>{" "}
                    {clientCompany?.phone || "+91 00000 00000"}
                  </p>
                  <p>
                    <strong>Email:</strong>{" "}
                    {clientCompany?.email || "contact@company.com"}
                  </p>
                  {clientCompany?.gst && (
                    <p>
                      <strong>GSTIN:</strong> {clientCompany.gst}
                    </p>
                  )}
                  <p className="print-address">
                    {clientCompany?.address || "Company Address"}
                  </p>
                </div>
              </div>
            </div>
            <div className="print-invoice-title-wrapper">
              <h2 className="print-invoice-title">INVOICE</h2>
            </div>
          </div>

          <div className="invoice-header-row print-bill-row">
            <div className="print-bill-to-col">
              <div className="print-bill-to-header">
                <span className="print-bill-to-label">Bill To:</span>
                <span className="print-party-name">{party?.name}</span>
              </div>
              <div className="print-party-details">
                {party?.address && <div>{party.address}</div>}
                {party?.gst && (
                  <div>
                    <strong>GSTIN:</strong> {party.gst}
                  </div>
                )}
                {party?.mobile && (
                  <div>
                    <strong>Mobile:</strong> {party.mobile}
                  </div>
                )}
              </div>
            </div>
            <div className="print-meta-col">
              <p>
                <strong>Date:</strong>{" "}
                {new Date(voucher.date).toLocaleDateString()}
              </p>
              <p>
                <strong>Invoice No:</strong>{" "}
                {voucher.invoiceNumber || voucher.fallbackInvoiceNumber}
              </p>
            </div>
          </div>

          {/* Table */}
          <div className="invoice-table-container">
            <table className="invoice-table print-table-wrapper">
              <thead>
                <tr className="print-thead-row">
                  <th className="print-th-left">Sr No.</th>
                  <th className="print-th-left">Item </th>
                  <th className="print-th-right">Price</th>
                  <th className="print-th-center">Qty</th>
                  <th className="print-th-right">Total</th>
                </tr>
              </thead>
              <tbody>
                {voucher.items.map((item, index) => (
                  <tr key={index}>
                    <td data-label="Sr No." className="print-td-default">
                      {index + 1}
                    </td>
                    <td data-label="Item" className="print-td-default">
                      {item.name}
                      {item.hsn && (
                        <div className="print-hsn-helper">HSN: {item.hsn}</div>
                      )}
                    </td>
                    <td data-label="Price" className="print-td-right">
                      Ôé╣{Number(item.price || 0).toFixed(2)}
                    </td>
                    <td data-label="Qty" className="print-td-center">
                      {item.qty} {item.unit}
                    </td>
                    <td data-label="Total" className="print-td-right">
                      Ôé╣{Number(item.amount || 0).toFixed(2)}
                    </td>
                  </tr>
                ))}
              </tbody>
              <tfoot>
                <tr className="print-tfoot-row">
                  <td colSpan="4" className="print-tfoot-label">
                    Total
                  </td>
                  <td className="print-tfoot-value">
                    Ôé╣{calculateTotal(voucher.items).toFixed(2)}
                  </td>
                </tr>
              </tfoot>
            </table>
          </div>

          <div className="print-footer-layout">
            <div className="print-footer-left">
              <div className="print-bottom-payment-details">
                <div className="print-payment-line">
                  <strong>Status:</strong>{" "}
                  <span
                    className={`print-status-text ${voucher.status?.toLowerCase() || "unpaid"}`}
                  >
                    {voucher.status || "Unpaid"}
                  </span>
                  {voucher.status !== "Unpaid" && (
                    <span className="print-payment-method-text">
                      / {voucher.paymentMethod || "Cash"}
                    </span>
                  )}
                </div>

                {voucher.status === "Partial" && (
                  <div className="print-detailed-summary">
                    <div className="print-detailed-row">
                      <span>Total Amount:</span>
                      <strong>
                        Ôé╣{calculateTotal(voucher.items).toFixed(2)}
                      </strong>
                    </div>
                    <div className="print-detailed-row">
                      <span>Amount Paid:</span>
                      <strong>
                        Ôé╣{Number(voucher.paidAmount || 0).toFixed(2)}
                      </strong>
                    </div>
                    <div className="print-detailed-row">
                      <span>Balance Due:</span>
                      <strong className="print-balance-due-text">
                        Ôé╣{Number(voucher.remainingAmount || 0).toFixed(2)}
                      </strong>
                    </div>
                  </div>
                )}
              </div>

              {/* Footer Notes */}
              {voucher.note && (
                <div className="print-notes-container">
                  <h4 className="print-notes-heading">Notes:</h4>
                  <p className="print-notes-body">{voucher.note}</p>
                </div>
              )}
            </div>

            <div className="print-signatory-wrapper">
              {clientCompany?.signature && (
                <div className="print-signatory-img-wrapper print-img-spacing">
                  <img
                    src={clientCompany.signature}
                    alt="Authorized Signature"
                    className="print-signatory-img"
                  />
                </div>
              )}
              <p className="print-signatory-line">Authorized Signatory</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default VoucherPrint;

import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Vouchers.css";
import {
  Plus,
  QrCode,
  Edit,
  Trash2,
  Search,
  Hash,
  Calendar,
  Package,
  IndianRupee,
  X,
  Filter,
  CreditCard,
} from "lucide-react";
import QRCode from "react-qr-code";
import Select from "react-select";
import {
  collection,
  getDocs,
  deleteDoc,
  doc,
  query,
  where,
  updateDoc,
} from "firebase/firestore";
import { getDB } from "../firebase";

function Vouchers() {
  const db = getDB();
  const [vouchers, setVouchers] = useState([]);
  const [search, setSearch] = useState("");
  const [showFilterModal, setShowFilterModal] = useState(false);
  const [filters, setFilters] = useState({
    dateFrom: "",
    dateTo: "",
    priceMin: 0,
    priceMax: 200000,
    sortInvoice: "desc", // "desc", "asc"
    sortParty: "", // "", "asc", "desc"
    status: "", // "", "Paid", "Unpaid", "Partial"
    paymentMethod: "", // "", "Cash", "Online"
  });
  const [qrVoucher, setQrVoucher] = useState(null);
  const [statusModalVoucher, setStatusModalVoucher] = useState(null);
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [tempStatusData, setTempStatusData] = useState({
    status: "",
    paidAmount: 0,
  });
  const navigate = useNavigate();

  useEffect(() => {
    const fetchVouchers = async () => {
      try {
        const q = query(
          collection(db, "vouchers"),
          where(
            "companyId",
            "==",
            JSON.parse(localStorage.getItem("loggedCompany"))?.id,
          ),
        );
        const querySnapshot = await getDocs(q);
        let data = querySnapshot.docs.map((doc) => ({
          id: doc.id,
          ...doc.data(),
        }));
        // Sort by creation time (ascending) to maintain consistent index
        data.sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
        // Reverse so newest is first, but assign originalIndex based on ascending order
        const processed = data
          .map((v, i) => ({ ...v, originalIndex: i }))
          .reverse();
        setVouchers(processed);
      } catch (error) {
        console.error("Error fetching vouchers:", error);
      }
    };
    fetchVouchers();
  }, []);

  const handleStatusUpdate = async () => {
    if (!statusModalVoucher) return;
    setUpdatingStatus(true);
    try {
      const total = calculateTotal(statusModalVoucher.items);
      let updates = {
        status: tempStatusData.status,
        paidAmount: parseFloat(tempStatusData.paidAmount) || 0,
      };

      if (updates.status === "Paid") {
        updates.paidAmount = total;
        updates.remainingAmount = 0;
      } else if (updates.status === "Unpaid") {
        updates.paidAmount = 0;
        updates.remainingAmount = total;
      } else if (updates.status === "Partial") {
        if (updates.paidAmount >= total && total > 0) {
          updates.status = "Paid";
          updates.paidAmount = total;
          updates.remainingAmount = 0;
        } else if (updates.paidAmount <= 0) {
          updates.status = "Unpaid";
          updates.paidAmount = 0;
          updates.remainingAmount = total;
        } else {
          updates.remainingAmount = total - updates.paidAmount;
        }
      }

      await updateDoc(doc(db, "vouchers", statusModalVoucher.id), updates);
      setVouchers(
        vouchers.map((v) =>
          v.id === statusModalVoucher.id ? { ...v, ...updates } : v,
        ),
      );
      setStatusModalVoucher(null);
    } catch (error) {
      console.error("Error updating status:", error);
      alert("Failed to update status.");
    } finally {
      setUpdatingStatus(false);
    }
  };

  const handleDelete = async (index, id) => {
    if (window.confirm("Are you sure you want to delete this voucher?")) {
      try {
        await deleteDoc(doc(db, "vouchers", id));
        const updated = vouchers.filter((v) => v.id !== id);
        setVouchers(updated);
      } catch (error) {
        console.error("Error deleting voucher:", error);
      }
    }
  };

  const calculateTotal = (items) => {
    return items.reduce((sum, item) => sum + (item.amount || 0), 0);
  };

  let filtered = vouchers.filter((v) => {
    // Basic Search
    const searchLower = search.toLowerCase();
    const invNo = String(
      v.invoiceNumber ||
        `INV/25-26/${String(v.originalIndex + 1).padStart(3, "0")}`,
    ).toLowerCase();

    const matchesSearch =
      (v.partyId && v.partyId.toLowerCase().includes(searchLower)) ||
      invNo.includes(searchLower);

    // Advanced Filters
    let matchesDateRange = true;
    if (filters.dateFrom || filters.dateTo) {
      const vDate = new Date(v.date);
      vDate.setHours(0, 0, 0, 0);

      if (filters.dateFrom) {
        const fromDate = new Date(filters.dateFrom);
        fromDate.setHours(0, 0, 0, 0);
        if (vDate < fromDate) matchesDateRange = false;
      }
      if (filters.dateTo) {
        const toDate = new Date(filters.dateTo);
        toDate.setHours(23, 59, 59, 999);
        if (vDate > toDate) matchesDateRange = false;
      }
    }

    let matchesPrice = true;
    const total = calculateTotal(v.items);
    if (filters.priceMin > 0 && total < filters.priceMin) matchesPrice = false;
    if (filters.priceMax < 200000 && total > filters.priceMax)
      matchesPrice = false;

    let matchesStatus = true;
    if (filters.status && v.status !== filters.status) matchesStatus = false;

    let matchesMethod = true;
    if (filters.paymentMethod && v.paymentMethod !== filters.paymentMethod)
      matchesMethod = false;

    return (
      matchesSearch &&
      matchesDateRange &&
      matchesPrice &&
      matchesStatus &&
      matchesMethod
    );
  });

  // Sorting
  filtered.sort((a, b) => {
    // 1. Sort by Party Name if selected
    if (filters.sortParty === "asc") {
      const cmp = (a.partyId || "").localeCompare(b.partyId || "");
      if (cmp !== 0) return cmp;
    } else if (filters.sortParty === "desc") {
      const cmp = (b.partyId || "").localeCompare(a.partyId || "");
      if (cmp !== 0) return cmp;
    }

    // 2. Fallback / Default sort by Invoice order
    const isAsc = filters.sortInvoice === "asc";
    const dateA = a.createdAt || new Date(a.date).getTime();
    const dateB = b.createdAt || new Date(b.date).getTime();
    return isAsc ? dateA - dateB : dateB - dateA;
  });

  const activeFiltersArr = [
    filters.dateFrom || filters.dateTo,
    filters.priceMin > 0 || filters.priceMax < 200000,
    filters.sortInvoice !== "desc",
    filters.sortParty !== "",
    filters.status !== "",
    filters.paymentMethod !== "",
  ].filter(Boolean);
  const activeFilterCount = activeFiltersArr.length;
  const hasActiveFilters = activeFilterCount > 0;

  return (
    <div className="vouchers-page">
      <div className="fixed-header root-page-header">
        <div className="search-bar w-full-search vouchers-search-wrap">
          <Search className="search-icon" size={18} />
          <input
            className="form-input"
            value={search}
            placeholder="Search by Party Name, Invoice No..."
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="vouchers-header-actions">
          <button
            className={`btn btn-icon vouchers-filter-btn filter-btn-wrapper ${hasActiveFilters ? "btn-primary" : "btn-outline-primary"}`}
            onClick={() => setShowFilterModal(true)}
            title="Filter Options"
          >
            <Filter size={23} />
            {activeFilterCount > 0 && (
              <span className="filter-badge">{activeFilterCount}</span>
            )}
          </button>
          <Link
            to="/add-voucher"
            className="btn btn-outline-primary btn-icon vouchers-add-btn"
            title="Create Voucher"
          >
            <Plus size={23} />
          </Link>
        </div>
      </div>

      <div className="content-below-fixed">
        <div className="grid grid-2">
          {filtered.length > 0 ? (
            filtered.map((v) => (
              <div
                key={v.id}
                className="voucher-card"
                onClick={() => navigate(`/voucher-print/${v.id}`)}
              >
                <div className="voucher-card-header">
                  <div className="voucher-card-title-group">
                    <h4 className="voucher-card-title voucher-card-title-cutoff">
                      {v.partyId}
                    </h4>
                    <span
                      className={`status-badge ${v.status?.toLowerCase() || "unpaid"}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        setStatusModalVoucher(v);
                        setTempStatusData({
                          status: v.status || "Unpaid",
                          paidAmount: v.paidAmount || 0,
                        });
                      }}
                      title="Click to update status"
                    >
                      {v.status || "Unpaid"}
                    </span>
                  </div>
                  <div className="voucher-card-actions">
                    <button
                      className="btn btn-action-print"
                      onClick={(e) => {
                        e.stopPropagation();
                        setQrVoucher(v);
                      }}
                      title="Show QR Code"
                    >
                      <QrCode size={16} />
                    </button>
                    <button
                      className="btn btn-action-edit"
                      onClick={(e) => {
                        e.stopPropagation();
                        navigate(`/add-voucher/${v.id}`);
                      }}
                      title="Edit"
                    >
                      <Edit size={16} />
                    </button>
                    <button
                      className="btn btn-action-delete"
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDelete(v.originalIndex, v.id);
                      }}
                      title="Delete"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>

                <div className="voucher-card-details">
                  <div className="voucher-meta-grid">
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Hash size={14} />
                      </div>
                      <p>
                        {v.invoiceNumber ||
                          `INV/25-26/${String(v.originalIndex + 1).padStart(3, "0")}`}
                      </p>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Calendar size={14} />
                      </div>
                      <p>{new Date(v.date).toLocaleDateString()}</p>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <CreditCard size={14} />
                      </div>
                      <p>{v.paymentMethod || "Cash"}</p>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Package size={14} />
                      </div>
                      <p>{v.items.length} Items</p>
                    </div>
                  </div>

                  <div className="voucher-card-footer">
                    <div className="voucher-price-info">
                      <span className="price-label">Total Amount</span>
                      <strong className="voucher-total-highlight">
                        Ôé╣{calculateTotal(v.items).toFixed(2)}
                      </strong>
                    </div>
                    {v.status === "Partial" && (
                      <div className="voucher-remaining-info">
                        <span className="price-label">Remaining</span>
                        <span className="remaining-value">
                          Ôé╣
                          {(v.remainingAmount !== undefined
                            ? v.remainingAmount
                            : calculateTotal(v.items)
                          ).toFixed(2)}
                        </span>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="no-vouchers-message">No vouchers found.</div>
          )}
        </div>
      </div>

      {qrVoucher && (
        <div className="qr-modal-overlay" onClick={() => setQrVoucher(null)}>
          <div
            className="qr-modal-content"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="qr-modal-header">
              <h3>Scan to View Invoice</h3>
              <button
                className="qr-modal-close"
                onClick={() => setQrVoucher(null)}
              >
                <X size={20} />
              </button>
            </div>
            <div className="qr-modal-body">
              <QRCode
                value={`${window.location.origin}/voucher-print/${qrVoucher.id}`}
                size={220}
                className="qr-code-img"
              />
              <p className="qr-modal-id">
                {qrVoucher.invoiceNumber ||
                  `INV/25-26/${String(qrVoucher.originalIndex + 1).padStart(3, "0")}`}
              </p>
              <p className="qr-modal-help">
                Scan this QR code with any mobile camera to view and download
                the invoice.
              </p>
            </div>
          </div>
        </div>
      )}

      {showFilterModal && (
        <div
          className="qr-modal-overlay"
          onClick={() => setShowFilterModal(false)}
        >
          <div
            className="qr-modal-content filter-modal-content"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="qr-modal-header">
              <h3>Filter Options</h3>
              <button
                className="qr-modal-close"
                onClick={() => setShowFilterModal(false)}
              >
                <X size={20} />
              </button>
            </div>
            <div className="qr-modal-body filter-modal-body">
              <div className="form-group filter-form-group">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">
                    Date Range
                  </label>
                  {(filters.dateFrom || filters.dateTo) && (
                    <span
                      className="filter-clear-link"
                      onClick={() =>
                        setFilters({ ...filters, dateFrom: "", dateTo: "" })
                      }
                    >
                      Clear
                    </span>
                  )}
                </div>
                <div className="filter-date-inputs">
                  <input
                    type={filters.dateFrom ? "date" : "text"}
                    onFocus={(e) => {
                      e.target.type = "date";
                    }}
                    onClick={(e) => {
                      e.target.type = "date";
                      setTimeout(() => {
                        try {
                          e.target.showPicker();
                        } catch (err) {}
                      }, 50);
                    }}
                    onTouchStart={(e) => {
                      e.target.type = "date";
                      setTimeout(() => {
                        try {
                          e.target.showPicker();
                        } catch (err) {}
                      }, 50);
                    }}
                    onBlur={(e) => {
                      if (!e.target.value) e.target.type = "text";
                    }}
                    placeholder="dd-mm-yyyy"
                    className="form-input"
                    value={filters.dateFrom}
                    onChange={(e) =>
                      setFilters({ ...filters, dateFrom: e.target.value })
                    }
                  />
                  <span className="filter-date-separator">to</span>
                  <input
                    type={filters.dateTo ? "date" : "text"}
                    onFocus={(e) => {
                      e.target.type = "date";
                    }}
                    onClick={(e) => {
                      e.target.type = "date";
                      setTimeout(() => {
                        try {
                          e.target.showPicker();
                        } catch (err) {}
                      }, 50);
                    }}
                    onTouchStart={(e) => {
                      e.target.type = "date";
                      setTimeout(() => {
                        try {
                          e.target.showPicker();
                        } catch (err) {}
                      }, 50);
                    }}
                    onBlur={(e) => {
                      if (!e.target.value) e.target.type = "text";
                    }}
                    placeholder="dd-mm-yyyy"
                    className="form-input"
                    value={filters.dateTo}
                    onChange={(e) =>
                      setFilters({ ...filters, dateTo: e.target.value })
                    }
                  />
                </div>
              </div>

              <div className="form-group filter-form-group">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">Price</label>
                  {(filters.priceMin > 0 || filters.priceMax < 200000) && (
                    <span
                      className="filter-clear-link"
                      onClick={() =>
                        setFilters({
                          ...filters,
                          priceMin: 0,
                          priceMax: 200000,
                        })
                      }
                    >
                      Clear
                    </span>
                  )}
                </div>
                <div className="price-range-display">
                  Ôé╣{filters.priceMin.toLocaleString()} ÔÇô Ôé╣
                  {filters.priceMax.toLocaleString()}
                  {filters.priceMax >= 200000 ? "+" : ""}
                </div>
                <div className="range-slider-container">
                  <div
                    className="range-slider-track"
                    style={{
                      left: `${(filters.priceMin / 200000) * 100}%`,
                      right: `${100 - (filters.priceMax / 200000) * 100}%`,
                    }}
                  ></div>
                  <input
                    type="range"
                    min="0"
                    max="200000"
                    step="100"
                    value={filters.priceMin}
                    onChange={(e) => {
                      const val = Math.min(
                        Number(e.target.value),
                        filters.priceMax,
                      );
                      setFilters({ ...filters, priceMin: val });
                    }}
                    className="range-slider-thumb thumb-left"
                  />
                  <input
                    type="range"
                    min="0"
                    max="200000"
                    step="100"
                    value={filters.priceMax}
                    onChange={(e) => {
                      const val = Math.max(
                        Number(e.target.value),
                        filters.priceMin,
                      );
                      setFilters({ ...filters, priceMax: val });
                    }}
                    className="range-slider-thumb thumb-right"
                  />
                </div>
              </div>

              <div className="form-group filter-form-group">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">
                    Voucher Status
                  </label>
                  {filters.status !== "" && (
                    <span
                      className="filter-clear-link"
                      onClick={() => setFilters({ ...filters, status: "" })}
                    >
                      Reset
                    </span>
                  )}
                </div>
                <Select
                  menuPortalTarget={document.body}
                  options={[
                    { value: "", label: "All Statuses" },
                    { value: "Paid", label: "Paid" },
                    { value: "Unpaid", label: "Unpaid" },
                    { value: "Partial", label: "Partial" },
                  ]}
                  value={
                    filters.status
                      ? { value: filters.status, label: filters.status }
                      : { value: "", label: "All Statuses" }
                  }
                  onChange={(selected) =>
                    setFilters({ ...filters, status: selected.value })
                  }
                  className="react-select-container"
                  classNamePrefix="react-select"
                />
              </div>

              <div className="form-group filter-form-group">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">
                    Payment Method
                  </label>
                  {filters.paymentMethod !== "" && (
                    <span
                      className="filter-clear-link"
                      onClick={() =>
                        setFilters({ ...filters, paymentMethod: "" })
                      }
                    >
                      Reset
                    </span>
                  )}
                </div>
                <Select
                  menuPortalTarget={document.body}
                  options={[
                    { value: "", label: "All Methods" },
                    { value: "Cash", label: "Cash" },
                    { value: "Online", label: "Online" },
                  ]}
                  value={
                    filters.paymentMethod
                      ? {
                          value: filters.paymentMethod,
                          label: filters.paymentMethod,
                        }
                      : { value: "", label: "All Methods" }
                  }
                  onChange={(selected) =>
                    setFilters({ ...filters, paymentMethod: selected.value })
                  }
                  className="react-select-container"
                  classNamePrefix="react-select"
                />
              </div>

              <div className="form-group filter-form-group">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">
                    Sort By Invoice Date
                  </label>
                  {filters.sortInvoice !== "desc" && (
                    <span
                      className="filter-clear-link"
                      onClick={() =>
                        setFilters({ ...filters, sortInvoice: "desc" })
                      }
                    >
                      Reset
                    </span>
                  )}
                </div>
                <Select
                  menuPortalTarget={document.body}
                  options={[
                    { value: "desc", label: "Newest First" },
                    { value: "asc", label: "Oldest First" },
                  ]}
                  value={
                    filters.sortInvoice === "desc"
                      ? { value: "desc", label: "Newest First" }
                      : { value: "asc", label: "Oldest First" }
                  }
                  onChange={(selected) =>
                    setFilters({ ...filters, sortInvoice: selected.value })
                  }
                  className="react-select-container"
                  classNamePrefix="react-select"
                />
              </div>

              <div className="form-group filter-form-group-last">
                <div className="filter-group-header">
                  <label className="form-label filter-label-bold">
                    Sort By Party Name
                  </label>
                  {filters.sortParty !== "" && (
                    <span
                      className="filter-clear-link"
                      onClick={() => setFilters({ ...filters, sortParty: "" })}
                    >
                      Reset
                    </span>
                  )}
                </div>
                <Select
                  menuPortalTarget={document.body}
                  options={[
                    { value: "", label: "None" },
                    { value: "asc", label: "A to Z" },
                    { value: "desc", label: "Z to A" },
                  ]}
                  value={
                    filters.sortParty === "asc"
                      ? { value: "asc", label: "A to Z" }
                      : filters.sortParty === "desc"
                        ? { value: "desc", label: "Z to A" }
                        : { value: "", label: "None" }
                  }
                  onChange={(selected) =>
                    setFilters({ ...filters, sortParty: selected.value })
                  }
                  className="react-select-container"
                  classNamePrefix="react-select"
                />
              </div>

              <div className="filter-actions">
                <button
                  className="btn btn-outline-danger filter-btn-clear"
                  onClick={() => {
                    setFilters({
                      dateFrom: "",
                      dateTo: "",
                      priceMin: 0,
                      priceMax: 200000,
                      sortInvoice: "desc",
                      sortParty: "",
                      status: "",
                      paymentMethod: "",
                    });
                    setShowFilterModal(false);
                  }}
                >
                  Clear
                </button>
                <button
                  className="btn btn-primary filter-btn-apply"
                  onClick={() => setShowFilterModal(false)}
                >
                  Apply
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
      {statusModalVoucher && (
        <div
          className="qr-modal-overlay"
          onClick={() => setStatusModalVoucher(null)}
        >
          <div
            className="qr-modal-content filter-modal-content status-modal-content"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="qr-modal-header">
              <h3>Update Status</h3>
              <button
                className="qr-modal-close"
                onClick={() => setStatusModalVoucher(null)}
              >
                <X size={20} />
              </button>
            </div>
            <div className="qr-modal-body filter-modal-body">
              <div className="form-group filter-form-group">
                <label className="form-label filter-label-bold">Status</label>
                <Select
                  menuPortalTarget={document.body}
                  isSearchable={false}
                  options={[
                    { value: "Paid", label: "Paid" },
                    { value: "Partial", label: "Partial" },
                    { value: "Unpaid", label: "Unpaid" },
                  ]}
                  value={{
                    value: tempStatusData.status,
                    label: tempStatusData.status,
                  }}
                  onChange={(selected) =>
                    setTempStatusData({
                      ...tempStatusData,
                      status: selected.value,
                      paidAmount:
                        selected.value === "Paid"
                          ? calculateTotal(statusModalVoucher.items)
                          : selected.value === "Unpaid"
                            ? 0
                            : tempStatusData.paidAmount,
                    })
                  }
                  className="react-select-container"
                  classNamePrefix="react-select"
                />
              </div>

              {tempStatusData.status === "Partial" && (
                <div className="form-group filter-form-group">
                  <label className="form-label filter-label-bold">
                    Amount Paid (Ôé╣)
                  </label>
                  <input
                    type="number"
                    className="form-input"
                    min="0"
                    value={tempStatusData.paidAmount}
                    onChange={(e) => {
                      let val = e.target.value;
                      if (val === "") {
                        setTempStatusData({
                          ...tempStatusData,
                          paidAmount: "",
                        });
                        return;
                      }
                      let num = parseFloat(val) || 0;
                      const total = calculateTotal(statusModalVoucher.items);
                      if (num < 0) num = 0;
                      else if (total > 0 && num > total) num = total;

                      let finalVal = val;
                      if (
                        parseFloat(val) < 0 ||
                        (total > 0 && parseFloat(val) > total)
                      ) {
                        finalVal = num;
                      }
                      setTempStatusData({
                        ...tempStatusData,
                        paidAmount: finalVal,
                      });
                    }}
                  />
                  <div className="status-modal-balance">
                    Balance: Ôé╣
                    {(
                      calculateTotal(statusModalVoucher.items) -
                      (parseFloat(tempStatusData.paidAmount) || 0)
                    ).toFixed(2)}
                  </div>
                </div>
              )}

              <div className="filter-actions status-modal-actions">
                <button
                  className="btn btn-outline-danger filter-btn-clear"
                  onClick={() => setStatusModalVoucher(null)}
                >
                  Cancel
                </button>
                <button
                  className="btn btn-primary filter-btn-apply"
                  onClick={handleStatusUpdate}
                  disabled={updatingStatus}
                >
                  {updatingStatus ? "Updating..." : "Update Status"}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Vouchers;

import React, { useState, useEffect } from "react";
import {
  collection,
  addDoc,
  getDocs,
  deleteDoc,
  doc,
  updateDoc,
  serverTimestamp,
  query,
  where,
  writeBatch,
} from "firebase/firestore";
import { mainDb as db, getTenantDb } from "../firebase";
import {
  Trash2,
  Plus,
  Building,
  LogOut,
  Edit2,
  Search,
  Phone,
  Key,
  Mail,
  FileText,
  MapPin,
  Image as ImageIcon,
  Eye,
  EyeOff,
} from "lucide-react";
import { useNavigate } from "react-router-dom";
import "./VendorDashboard.css";

const VendorDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [companyName, setCompanyName] = useState("");
  const [pin, setPin] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [gst, setGst] = useState("");
  const [address, setAddress] = useState("");
  const [logo, setLogo] = useState("");
  const [signature, setSignature] = useState("");
  const [fbApiKey, setFbApiKey] = useState("");
  const [fbAuthDomain, setFbAuthDomain] = useState("");
  const [fbProjectId, setFbProjectId] = useState("");
  const [fbStorageBucket, setFbStorageBucket] = useState("");
  const [fbMessagingSenderId, setFbMessagingSenderId] = useState("");
  const [fbAppId, setFbAppId] = useState("");

  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showFormPin, setShowFormPin] = useState(false);
  const [visiblePins, setVisiblePins] = useState({});
  const navigate = useNavigate();

  useEffect(() => {
    fetchCompanies();
  }, []);

  const fetchCompanies = async () => {
    try {
      // 1. First run the fetch as normal
      const querySnapshot = await getDocs(collection(db, "companies"));
      let data = querySnapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
      }));

      // 2. Data Migration: Check if old localStorage 'companies' exists
      const localCompaniesRaw = localStorage.getItem("companies");
      if (localCompaniesRaw) {
        try {
          const localCompanies = JSON.parse(localCompaniesRaw);
          if (Array.isArray(localCompanies) && localCompanies.length > 0) {
            console.log("Migrating local storage companies to Firebase...");
            let migratedCount = 0;

            for (const lc of localCompanies) {
              // Only migrate if the userId doesn't already exist in Firebase
              const exists = data.find((dc) => dc.phone === lc.phone);
              if (!exists && lc.phone && (lc.pin || lc.password)) {
                const docRef = await addDoc(collection(db, "companies"), {
                  companyName: lc.companyName || lc.phone,
                  pin: lc.pin || lc.password,
                  email: lc.email || "",
                  phone: lc.phone || "",
                  gst: lc.gst || "",
                  address: lc.address || "",
                  logo: lc.logo || "",
                  signature: lc.signature || "",
                  firebaseConfig: lc.firebaseConfig || "",
                  isActive: lc.isActive !== false,
                  createdAt: serverTimestamp(),
                });

                // Add the newly migrated company to our local array state
                data.push({
                  id: docRef.id,
                  companyName: lc.companyName || lc.phone,
                  pin: lc.pin || lc.password,
                  email: lc.email || "",
                  phone: lc.phone || "",
                  gst: lc.gst || "",
                  address: lc.address || "",
                  logo: lc.logo || "",
                  signature: lc.signature || "",
                  isActive: lc.isActive !== false,
                });
                migratedCount++;
              }
            }
            // Once migration is complete, clear the old localStorage key
            if (migratedCount > 0) {
              alert(
                `Successfully migrated ${migratedCount} existing companies from local storage to Firebase!`,
              );
            }
            localStorage.removeItem("companies");
          }
        } catch (e) {
          console.error("Error migrating local companies:", e);
        }
      }

      // Update state with fresh list
      setCompanies(data);
    } catch (error) {
      console.error("Error fetching companies: ", error);
      setError("Failed to load companies.");
    }
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        // 2MB limit
        setError("Logo image size should be less than 2MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogo(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSignatureUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        // 2MB limit
        setError("Signature image size should be less than 2MB.");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSignature(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddCompany = async (e) => {
    e.preventDefault();
    setError("");

    if (
      !companyName.trim() ||
      !pin ||
      !email.trim() ||
      !phone.trim() ||
      !gst.trim() ||
      !address.trim() ||
      !fbApiKey.trim() ||
      !fbAuthDomain.trim() ||
      !fbProjectId.trim() ||
      !fbStorageBucket.trim() ||
      !fbMessagingSenderId.trim() ||
      !fbAppId.trim()
    ) {
      setError("All fields including Firebase config are strictly required.");
      return;
    }

    // Email Validation
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Invalid email format.");
      return;
    }

    // Phone Validation (10 digits)
    if (!/^\d{10}$/.test(phone)) {
      setError("Phone number must be exactly 10 digits.");
      return;
    }

    // PIN Validation (4 digits)
    if (!/^\d{4}$/.test(pin)) {
      setError("PIN must be exactly 4 digits.");
      return;
    }

    // Check if Phone already exists
    const existingUser = companies.find(
      (c) => c.phone === phone && c.id !== editingId,
    );
    if (existingUser) {
      setError("Mobile Number already exists.");
      return;
    }

    let firebaseConfig = "";
    const fbObj = {
      apiKey: fbApiKey.trim(),
      authDomain: fbAuthDomain.trim(),
      projectId: fbProjectId.trim(),
      storageBucket: fbStorageBucket.trim(),
      messagingSenderId: fbMessagingSenderId.trim(),
      appId: fbAppId.trim(),
    };

    // Now we know all fields are present due to validation above
    firebaseConfig = JSON.stringify(fbObj);

    setIsSubmitting(true);
    try {
      if (editingId) {
        const docRef = doc(db, "companies", editingId);
        await updateDoc(docRef, {
          companyName,
          pin,
          email,
          phone,
          gst,
          address,
          logo,
          signature,
          firebaseConfig,
        });

        setCompanies(
          companies.map((c) =>
            c.id === editingId
              ? {
                  ...c,
                  companyName,
                  pin,
                  email,
                  phone,
                  gst,
                  address,
                  logo,
                  signature,
                  firebaseConfig,
                }
              : c,
          ),
        );
      } else {
        const docRef = await addDoc(collection(db, "companies"), {
          companyName,
          pin,
          email,
          phone,
          gst,
          address,
          logo,
          signature,
          firebaseConfig,
          isActive: true,
          createdAt: serverTimestamp(),
        });

        setCompanies([
          ...companies,
          {
            id: docRef.id,
            companyName,
            pin,
            email,
            phone,
            gst,
            address,
            logo,
            signature,
            firebaseConfig,
            isActive: true,
          },
        ]);
      }

      resetForm();
    } catch (error) {
      console.error("Error saving company:", error);
      setError("Failed to save company.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetForm = () => {
    setCompanyName("");
    setPin("");
    setEmail("");
    setPhone("");
    setGst("");
    setAddress("");
    setLogo("");
    setSignature("");
    setFbApiKey("");
    setFbAuthDomain("");
    setFbProjectId("");
    setFbStorageBucket("");
    setFbMessagingSenderId("");
    setFbAppId("");
    setIsAdding(false);
    setEditingId(null);
    setIsSubmitting(false);
    setShowFormPin(false);
  };

  const handleEditCompany = (company) => {
    setCompanyName(company.companyName);
    setPin(company.pin || company.password || "");
    setEmail(company.email || "");
    setPhone(company.phone || "");
    setGst(company.gst || "");
    setAddress(company.address || "");
    setLogo(company.logo || "");
    setSignature(company.signature || "");

    let parsedFb = {};
    if (company.firebaseConfig) {
      try {
        parsedFb = JSON.parse(company.firebaseConfig);
      } catch (e) {
        console.error("Failed to parse company firebase config for editing");
      }
    }
    setFbApiKey(parsedFb.apiKey || "");
    setFbAuthDomain(parsedFb.authDomain || "");
    setFbProjectId(parsedFb.projectId || "");
    setFbStorageBucket(parsedFb.storageBucket || "");
    setFbMessagingSenderId(parsedFb.messagingSenderId || "");
    setFbAppId(parsedFb.appId || "");

    setEditingId(company.id);
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDeleteCompany = async (company) => {
    if (
      window.confirm(
        `Are you sure you want to delete ${company.companyName}? This will permanently delete all data (Vouchers, Products, Parties) associated with this company.`,
      )
    ) {
      try {
        let hasValidConfig = false;
        if (company.firebaseConfig) {
          try {
            const parsed = JSON.parse(company.firebaseConfig);
            if (parsed && parsed.projectId) hasValidConfig = true;
          } catch (e) {}
        }

        // Helper function to safely delete documents in batches under a 400 limit
        const deleteDataWithBatches = async (targetDb) => {
          const collectionsToDelete = ["vouchers", "products", "parties"];
          let currentBatch = writeBatch(targetDb);
          let count = 0;

          // Delete from specific collections
          for (const collName of collectionsToDelete) {
            const q = query(
              collection(targetDb, collName),
              where("companyId", "==", company.id),
            );
            const snap = await getDocs(q);
            for (const docSnap of snap.docs) {
              currentBatch.delete(doc(targetDb, collName, docSnap.id));
              count++;
              if (count >= 400) {
                await currentBatch.commit();
                currentBatch = writeBatch(targetDb);
                count = 0;
              }
            }
          }

          // Delete login history subcollections
          const histColNames = ["login_history", "loginHistory"];
          for (const hCol of histColNames) {
            try {
              const hSnap = await getDocs(
                collection(targetDb, `companies/${company.id}/${hCol}`),
              );
              for (const docSnap of hSnap.docs) {
                currentBatch.delete(docSnap.ref);
                count++;
                if (count >= 400) {
                  await currentBatch.commit();
                  currentBatch = writeBatch(targetDb);
                  count = 0;
                }
              }
            } catch (e) {
              /* subcollection might not exist, silently ignore */
            }
          }

          if (count > 0) {
            await currentBatch.commit();
          }
        };

        if (hasValidConfig) {
          try {
            const tenantDb = getTenantDb(company.id, company.firebaseConfig);
            await deleteDataWithBatches(tenantDb);
          } catch (tenantErr) {
            console.error(
              "Warning: Failed to delete remote tenant DB data.",
              tenantErr,
            );
            // Non-fatal error so we continue and delete the company from main vendor list anyway.
          }
        }

        // ALWAYS delete the data from the MAIN database as well to ensure master is clean
        try {
          await deleteDataWithBatches(db);
        } catch (mainErr) {
          console.error("Warning: Failed to delete main DB data.", mainErr);
        }

        // Finally, delete the company itself from the MAIN db
        await deleteDoc(doc(db, "companies", company.id));

        setCompanies(companies.filter((c) => c.id !== company.id));
        alert("Company successfully deleted.");
      } catch (error) {
        console.error("Error deleting company:", error);
        alert("Failed to delete company.");
      }
    }
  };

  const handleToggleStatus = async (id, currentStatus, companyName) => {
    const actionText = currentStatus === false ? "activate" : "deactivate";
    if (
      !window.confirm(`Are you sure you want to ${actionText} ${companyName}?`)
    ) {
      return;
    }

    try {
      // If currentStatus is undefined, it means it's an old record without isActive field, so treat as true (active).
      const newStatus = currentStatus === false ? true : false;
      const docRef = doc(db, "companies", id);
      await updateDoc(docRef, { isActive: newStatus });
      setCompanies(
        companies.map((c) => (c.id === id ? { ...c, isActive: newStatus } : c)),
      );
    } catch (error) {
      console.error("Error toggling status:", error);
      alert("Failed to change company status.");
    }
  };

  const handleLogout = () => {
    // Basic logout logic for now
    navigate("/vendor");
  };

  const togglePinVisibility = (id) => {
    setVisiblePins((prev) => ({
      ...prev,
      [id]: !prev[id],
    }));
  };

  const filteredCompanies = companies.filter(
    (company) =>
      company.companyName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (company.phone && company.phone.includes(searchQuery)),
  );

  return (
    <div className="vd-dashboard-container">
      <header className="vd-header">
        <div className="vd-logo">
          <Building size={22} />
          <h3>Vendor Dashboard</h3>
        </div>
        <button
          className="btn btn-outline-primary vd-logout-btn"
          onClick={handleLogout}
        >
          <LogOut size={18} />
          {/* <span>Logout</span> */}
        </button>
      </header>

      <main className="vd-main">
        {!isAdding && (
          <div className="vd-action-bar">
            <div className="search-bar w-full-search vd-search-wrapper">
              <Search className="search-icon" size={18} />
              <input
                type="text"
                placeholder="Search company by Name or Phone..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="form-input vd-search-input"
              />
            </div>
            <button
              className="btn btn-outline-primary btn-icon vd-add-btn-wrapper"
              onClick={() => setIsAdding(true)}
              title="Add Company"
            >
              <Plus size={23} />
            </button>
          </div>
        )}

        {error && <div className="vd-error-alert">{error}</div>}

        {isAdding && (
          <div className="vd-add-card">
            <h4>{editingId ? "Edit Company details" : "Create New Company"}</h4>
            <form onSubmit={handleAddCompany} className="vd-form">
              <div className="vd-form-row">
                <div className="vd-input-group">
                  <label>
                    Company Name <span className="vd-required-asterisk">*</span>
                  </label>
                  <input
                    type="text"
                    value={companyName}
                    onChange={(e) => setCompanyName(e.target.value)}
                    placeholder="E.g. Tech Solutions"
                    required
                  />
                </div>
                <div className="vd-input-group">
                  <label>
                    Mobile Number{" "}
                    <span className="vd-required-asterisk">*</span>
                  </label>
                  <input
                    type="tel"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    placeholder="10-digit Mobile Number"
                    maxLength={10}
                    required
                  />
                </div>
                <div className="vd-input-group">
                  <label>
                    4-Digit PIN <span className="vd-required-asterisk">*</span>
                  </label>
                  <div className="vd-password-wrapper">
                    <input
                      type={showFormPin ? "text" : "password"}
                      value={pin}
                      onChange={(e) => setPin(e.target.value)}
                      placeholder="4-digit PIN"
                      maxLength={4}
                      pattern="\d{4}"
                      required
                      className="vd-password-input"
                    />
                    <button
                      type="button"
                      className="vd-password-toggle-btn"
                      onClick={() => setShowFormPin(!showFormPin)}
                      tabIndex="-1"
                    >
                      {showFormPin ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>
                <div className="vd-input-group">
                  <label>
                    Email <span className="vd-required-asterisk">*</span>
                  </label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Company Email"
                    required
                  />
                </div>
                <div className="vd-input-group">
                  <label>
                    GST No. <span className="vd-required-asterisk">*</span>
                  </label>
                  <input
                    type="text"
                    value={gst}
                    onChange={(e) => setGst(e.target.value.toUpperCase())}
                    placeholder="GSTIN"
                    maxLength={15}
                    required
                  />
                </div>
                <div className="vd-input-group vd-full-width-col">
                  <label>
                    Address <span className="vd-required-asterisk">*</span>
                  </label>
                  <textarea
                    value={address}
                    onChange={(e) => setAddress(e.target.value)}
                    placeholder="Full Business Address"
                    required
                    rows="3"
                  />
                </div>
                <div className="vd-input-group vd-full-width-col">
                  <label>
                    Firebase Web Config{" "}
                    <span className="vd-required-asterisk">*</span> (Separate
                    Fields)
                  </label>
                  <div className="vd-grid vd-fb-config-grid">
                    <input
                      type="text"
                      value={fbApiKey}
                      onChange={(e) => setFbApiKey(e.target.value)}
                      placeholder="apiKey"
                      required
                    />
                    <input
                      type="text"
                      value={fbAuthDomain}
                      onChange={(e) => setFbAuthDomain(e.target.value)}
                      placeholder="authDomain"
                      required
                    />
                    <input
                      type="text"
                      value={fbProjectId}
                      onChange={(e) => setFbProjectId(e.target.value)}
                      placeholder="projectId"
                      required
                    />
                    <input
                      type="text"
                      value={fbStorageBucket}
                      onChange={(e) => setFbStorageBucket(e.target.value)}
                      placeholder="storageBucket"
                      required
                    />
                    <input
                      type="text"
                      value={fbMessagingSenderId}
                      onChange={(e) => setFbMessagingSenderId(e.target.value)}
                      placeholder="messagingSenderId"
                      required
                    />
                    <input
                      type="text"
                      value={fbAppId}
                      onChange={(e) => setFbAppId(e.target.value)}
                      placeholder="appId"
                      required
                    />
                  </div>
                  <small className="vd-fb-config-helper">
                    Provide the Firebase Config keys for this company's DB. This
                    is Required to activate their custom DB as data is no longer
                    mixed in the main vendor DB.
                  </small>
                </div>
                <div className="vd-input-group vd-full-width-col">
                  <label>Logo (Optional)</label>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                  />
                  {logo && (
                    <div
                      className="vd-logo-preview-wrapper"
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        marginTop: "10px",
                      }}
                    >
                      <img
                        src={logo}
                        alt="Company Logo"
                        className="vd-logo-preview-img"
                      />
                      <button
                        type="button"
                        className="btn btn-outline-danger btn-icon"
                        onClick={() => setLogo("")}
                        title="Remove Logo"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  )}
                </div>
                <div className="vd-input-group vd-full-width-col">
                  <label>Authorized Signatory Image (Optional)</label>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleSignatureUpload}
                  />
                  {signature && (
                    <div
                      className="vd-logo-preview-wrapper"
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        marginTop: "10px",
                      }}
                    >
                      <img
                        src={signature}
                        alt="Signatory"
                        className="vd-logo-preview-img vd-signatory-img"
                      />
                      <button
                        type="button"
                        className="btn btn-outline-danger btn-icon"
                        onClick={() => setSignature("")}
                        title="Remove Signature"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  )}
                </div>
              </div>
              <div className="vd-form-actions vd-form-actions-wrapper">
                <button
                  type="submit"
                  className="btn btn-outline-primary btn-mobile-flex vd-form-action-btn-sized"
                  disabled={isSubmitting}
                >
                  {isSubmitting ? "Saving..." : editingId ? "Update" : "Save"}
                </button>
                <button
                  type="button"
                  className="btn btn-outline-danger btn-mobile-flex vd-form-action-btn-sized"
                  onClick={resetForm}
                  disabled={isSubmitting}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        )}

        {!isAdding && (
          <div className="vd-grid">
            {filteredCompanies.length > 0 ? (
              filteredCompanies.map((company) => (
                <div key={company.id} className="vd-card">
                  <div className="vd-card-header">
                    <div className="vd-card-title">
                      <Building className="vd-card-icon" size={20} />
                      <h4>{company.companyName}</h4>
                    </div>
                    <div className="vd-card-actions">
                      <button
                        className="btn btn-action-edit"
                        onClick={() => handleEditCompany(company)}
                        title="Edit Company"
                      >
                        <Edit2 size={16} />
                      </button>
                      <button
                        className="btn btn-action-delete"
                        onClick={() => handleDeleteCompany(company)}
                        title="Delete Company"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                  <div className="vd-card-body">
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Phone size={14} />
                      </div>
                      <p>{company.phone}</p>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Key size={14} />
                      </div>
                      <div className="vd-password-display-wrapper">
                        <p className="vd-mono">
                          {visiblePins[company.id]
                            ? company.pin || company.password
                            : "****"}
                        </p>
                        <button
                          className="vd-password-toggle-icon"
                          onClick={() => togglePinVisibility(company.id)}
                          title={
                            visiblePins[company.id] ? "Hide PIN" : "Show PIN"
                          }
                        >
                          {visiblePins[company.id] ? (
                            <EyeOff size={14} />
                          ) : (
                            <Eye size={14} />
                          )}
                        </button>
                      </div>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <Mail size={14} />
                      </div>
                      <p>{company.email}</p>
                    </div>
                    <div className="party-detail-row">
                      <div className="party-detail-icon">
                        <MapPin size={14} />
                      </div>
                      <p className="vd-address-text">{company.address}</p>
                    </div>
                  </div>
                  <div className="vd-card-footer vd-card-footer-spaced">
                    <span
                      className={`vd-status-badge ${company.isActive === false ? "inactive" : "active"}`}
                    >
                      {company.isActive === false ? "Deactive" : "Active"}
                    </span>
                    <button
                      className={`btn btn-outline ${company.isActive === false ? "btn-outline-primary" : "btn-outline-danger"} vd-status-btn-small`}
                      onClick={() =>
                        handleToggleStatus(
                          company.id,
                          company.isActive,
                          company.companyName,
                        )
                      }
                    >
                      {company.isActive === false
                        ? "Make Active"
                        : "Make Deactive"}
                    </button>
                  </div>
                </div>
              ))
            ) : (
              <div className="vd-empty-state">
                <Building size={48} className="vd-empty-icon" />
                <p>No companies found. Create one to get started.</p>
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default VendorDashboard;
